function ffmpegReady(): Promise<FFmpeg> {
    return new Promise((resolve, reject) => {
        if (ffmpeg && ffmpeg.loaded) resolve(ffmpeg)
        else ffmpegPoll.push({resolve: resolve, reject: reject})
    })
}

async function installSW() {
    let jsExists = false
    let tsExists = false
    await Promise.allSettled([
        fetch("./sw.js", {method: "HEAD"})
            .then(resp => {
                jsExists = resp.ok
            }),
        fetch("./noopsw.ts", {method: "HEAD"})
            .then(resp => {
                tsExists = resp.ok
            })
    ]).catch(_ => {
    })
    const url = jsExists ? "./sw.js" : tsExists ? "./noopsw.ts" : null
    if (tsExists && !jsExists) console.warn("trying to turn off the service worker by installing a no-op")
    if (!url) throw new Error("Could not find service worker definition")
    try {
        const registration = await navigator.serviceWorker.register(url, {
            type: "module",
        });
        if (registration.installing) {
            console.log("Service worker installing");
        } else if (registration.waiting) {
            console.log("Service worker installed");
        } else if (registration.active) {
            console.log("Service worker active");
        }
        return true
    } catch (error) {
        console.error(`Registration failed with ${error}`);
        return false
    }
}

