function _refreshFileKnown(row: IORow, file: TaggedFile) {
    row.changeInputDesc(file.description)
    row.el.dataset.state = file.state
}

function refreshFile(file: TaggedFile) {
    let row = io.getRow(file.id)
    if (!row) {
        row = file.row = io.newRow(file.id, file.file.name, file.description)
    }
    _refreshFileKnown(row, file)
}

function removeFile(file: TaggedFile) {
    const idx = workingSet.indexOf(file)
    if (idx !== -1) workingSet.splice(idx, 1)
    io.removeRow(file.id)
    // el.inputFiles.querySelector(`[data-id="${file.id}"]`)?.remove()
}

function refreshFileList() {
    for (const file of workingSet) {
        refreshFile(file)
    }
    if (workingSet.length > 0) {
        el.inputManipulators.classList.remove('hidden')
    } else {
        el.inputManipulators.classList.add('hidden')
    }
    if (workingSet.some(it => it.state === "unusable")) {
        el.clearInvalidBtn.classList.remove('hidden')
    } else {
        el.clearInvalidBtn.classList.add('hidden')
    }
}

function addFile(file: File) {
    console.log(file)
    const id = crypto.randomUUID()
    const row = io.newRow(id, file.name, "not sure what this is yet, hold on")
    const item: TaggedFile = {
        file: file,
        id: id,
        description: "not sure what this is yet, hold on",
        state: "analyze" as const,
        row: row
    };
    workingSet.push(item)
    refreshFileList()
}

el.clearInputsBtn.addEventListener('click', () => {
    workingSet.length = 0
    refreshFileList()
})

el.clearInvalidBtn.addEventListener('click', () => {
    workingSet
        .filter(it => it.state === "unusable")
        .forEach(removeFile)
    refreshFileList()
})

function handleDrop(ev: DragEvent) {
    ev.preventDefault()
    const files = [...ev.dataTransfer!.items]
    const entries = files
        .filter(
            it => it && (it.webkitGetAsEntry && it.webkitGetAsEntry() || it.getAsEntry && it.getAsEntry()) instanceof FileSystemFileEntry
        )
        .map(it => it.getAsFile())
        .filter(it => it !== null)
    entries.forEach(addFile)
    refreshFileList()
    el.drop.classList.remove("-hint")
}

// Set up the dropzone
el.drop.addEventListener("drop", handleDrop)
window.addEventListener("drop", e => {
    console.log('window', e)
    // thanks MDN https://developer.mozilla.org/en-US/docs/Web/API/HTML_Drag_and_Drop_API/File_drag_and_drop
    // el.drop.classList.remove("-hint")
    if ([...e.dataTransfer!.items].some((item) => item.kind === "file")) {
        e.preventDefault();
    }
})
el.drop.addEventListener("dragover", e => {
    const transfer = e.dataTransfer!;
    const fileItems = [...transfer.items].filter(
        (item) => item.kind === "file",
    );
    if (fileItems.length > 0) {
        e.preventDefault();
        transfer.dropEffect = "copy";
    }
})
window.addEventListener("dragover", e => {
    const transfer = e.dataTransfer!
    const fileItems = [...transfer.items].filter(
        (item) => item.kind === "file",
    );
    if (fileItems.length > 0) {
        e.preventDefault();
        if (!el.drop.contains(e.target as Node)) {
            transfer.dropEffect = "none";
        }
        el.drop.classList.add("-hint")
    } else {
        el.drop.classList.remove("-hint")
    }
});
el.dropInput.addEventListener("change", e => {
    const target = e.target as HTMLInputElement;
    for (const file of target.files!) {
        addFile(file)
    }
    refreshFileList()
    target.value = "";
})
window.addEventListener("dragleave", () => el.drop.classList.remove("-hint"));
window.addEventListener("dragend", () => el.drop.classList.remove("-hint"));

function failFile(file: TaggedFile, reason: any) {
    console.error(reason)
    file.state = "unusable"
    file.description = `can't process this file: ${reason}`
    refreshFileList()
    return
}

function matchStrOrNull(s: string, re: RegExp): string | null {
    const result = s.match(re)
    if (!result || !result[1]) return null
    return result[1]
}

function matchNumOrNull(s: string, re: RegExp): number | null {
    const result = s.match(re)
    if (!result || !result[1]) return null
    const value = parseFloat(result[1])
    if (isNaN(value)) return null
    return value
}

class AudioCodec implements Codec {
    name: string;
    type: "audio"
    channels: number
    duration: number | null
    bitRate: number | null

    constructor(probe: string) {
        this.type = "audio"
        this.name = matchStrOrNull(probe, /codec_name=(.+)/)!
        this.channels = matchNumOrNull(probe, /channels=(\d+)/)!
        this.duration = matchNumOrNull(probe, /duration=(\d+(?:\.\d+)?)/)
        this.bitRate = matchNumOrNull(probe, /bit_rate=(\d+(?:\.\d+)?)/)
    }

    describe(): string {
        let channelName: string
        switch (this.channels) {
            case 0:
                channelName = "uhh"
                break
            case 1:
                channelName = "mono"
                break
            case 2:
                channelName = "stereo"
                break
            default:
                channelName = "surround?"
                break
        }
        const durationStr = this.duration === null ? "unknown duration" : `${this.duration.toFixed(2)}s`
        return `${this.name} audio: ${durationStr} / ${this.channels} channel${this.channels == 1 ? '' : 's'} (${channelName}) @ ${this.bitRate} bps`;
    }
}

class VideoCodec implements Codec {
    name: string;
    type: "video"
    width: number
    height: number
    duration: number | null
    bitRate: number | null

    constructor(probe: string) {
        this.type = "video"
        this.name = matchStrOrNull(probe, /codec_name=(.+)/)!
        this.width = matchNumOrNull(probe, /width=(\d+)/)!
        this.height = matchNumOrNull(probe, /height=(\d+)/)!
        this.duration = matchNumOrNull(probe, /duration=(\d+(?:\.\d+)?)/)
        this.bitRate = matchNumOrNull(probe, /bit_rate=(\d+(?:\.\d+)?)/)
    }

    describe(): string {
        const durationStr = this.duration === null ? "unknown duration" : `${this.duration.toFixed(2)}s`
        return `${this.name} video: ${durationStr} / ${this.width}x${this.height} @ ${this.bitRate} bps`;
    }
}

const knownCodecs = {
    audio: AudioCodec,
    video: VideoCodec
} as const

function analyzeStreams(probe: string, file: TaggedFile) {
    const regexp = /\[STREAM]\s*([\w\W]*?)\s*\[\/STREAM]/gm
    const chunks: string[] = []
    let m: RegExpExecArray | null
    while ((m = regexp.exec(probe)) !== null) {
        if (m.index === regexp.lastIndex) regexp.lastIndex++;
        chunks.push(m[1])
    }
    const results: Codec[] = []
    for (const chunk of chunks) {
        const type = chunk.match(/codec_type=(\w+)/)
        if (!type || !type[1]) {
            console.warn(`can't determine codec type for a chunk in ${file.id}`)
            continue
        }
        const codec = knownCodecs[type[1] as keyof typeof knownCodecs];
        if (!codec) {
            console.warn(`not interpreting codec of type ${type[1]}`)
            continue
        }
        results.push(new codec(chunk))
    }
    return results
}

async function processAnalyze(file: TaggedFile) {
    if (file.state !== "analyze") throw "wrong state dumbass"
    file.state = "analyzing"
    file.description = "waiting for FFmpeg..."
    refreshFile(file)
    const ffmpeg = await ffmpegReady()
    file.description = "working on it..."
    refreshFile(file)
    await ffmpeg.writeFile(file.id, await fetchFile(file.file))
    const statFile = `${file.id}-stat.txt`
    await ffmpeg.ffprobe([
        '-v', 'error',
        '-show_entries',
        'stream',
        file.id,
        '-o', statFile
    ])
    try {
        const data = new TextDecoder().decode(await ffmpeg.readFile(statFile) as Uint8Array)
        const streams = analyzeStreams(data, file)

        file.state = "ready"
        const desc: string[] = [];
        if (streams.length === 0) {
            return failFile(file, "no a/v media detected")
        }
        for (const stream of streams) {
            desc.push(stream.describe())
        }
        file.description = desc.join('\n')
        refreshFileList()
    } catch (e) {
        return failFile(file, e)
    } finally {
        // noinspection ES6MissingAwait
        ffmpeg.deleteFile(statFile)
    }
}

function step() {
    for (const file of workingSet) {
        switch (file.state) {
            case "analyze": // noinspection JSIgnoredPromiseFromCall
                processAnalyze(file)
                break;
        }
    }
}

setInterval(step, 100)
