import {ICON_CLEAR} from "./page_content.ts";
import type {AbstractIORow} from "./common.d.ts";

function generateColor(): string {
    const hole = 218 - 182
    let hue = Math.random() * (360 - hole)
    if (hue > hole) hue += hole
    return hue.toFixed(2) + "deg";
}

export class IORow implements AbstractIORow {
    readonly id: string;
    readonly el: HTMLElement
    private valid = false
    private onRemovedCallbacks: ((row: IORow) => void)[] = []

    constructor(container: HTMLElement, id: string, name: string, initialDescription: string) {
        this.id = id
        this.el = document.createElement("li")
        this.el.innerHTML = `
<div class="input-file">
    <div class="-name">${name}</div>
    <button class="-remove"><img src="${ICON_CLEAR}" alt="Remove input"></button>
    <div class="-desc">${initialDescription}</div>
</div>
<div class="output-file"></div>
        `
        this.el.classList.add("-row")
        container.appendChild(this.el)
        this.el.querySelector(".-remove")?.addEventListener("click", () => {
            this.onRemovedCallbacks.forEach(it => it(this))
        })
        this.el.style.setProperty("--hue", generateColor())
        this.clearOutput()
        this.valid = true
    }

    changeInputDesc(desc: string) {
        const el = this.el.querySelector(".-desc")! as HTMLElement
        el.innerText = desc
    }

    clearOutput() {
        const noOutput = document.createElement("div")
        noOutput.classList.add("output-file")
        noOutput.classList.add("no-output-file")
        noOutput.innerText = "[no output]"
        this.el.querySelector(".output-file")?.replaceWith(noOutput)
    }

    onRemoved(action: (row: IORow) => void) {
        this.onRemovedCallbacks.push(action)
    }

    isValid() {
        return this.valid
    }

    removeVisuals() {
        this.valid = false
        this.el.remove()
    }
}

export class IOPanel {
    private readonly around: HTMLElement
    private rows: Map<String, IORow> = new Map()

    constructor(around: HTMLElement) {
        this.around = around
    }

    getRow(id: string): IORow | undefined {
        return this.rows.get(id)
    }

    removeRow(id: string) {
        const before = this.rows.get(id)
        if (before) before.removeVisuals()
        this.rows.delete(id)
    }

    newRow(id: string, name: string, desc: string): IORow {
        const row = new IORow(this.around, id, name, desc);
        row.onRemoved(it => {
            this.removeRow(it.id)
        })
        this.rows.set(id, row)
        return row
    }
}